public class Solution {
    private int cameras = 0;
    // 0=not covered, 1=has camera, 2=covered
    public int minCameraCover(TreeNode root) {
        if (dfs(root) == 0) cameras++; // root not covered → add camera
        return cameras;
    }
    private int dfs(TreeNode node) {
        if (node == null) return 2; // null nodes are 'covered' by default
        int left  = dfs(node.left);
        int right = dfs(node.right);
        if (left == 0 || right == 0) { cameras++; return 1; } // child not covered
        if (left == 1 || right == 1) return 2; // covered by child's camera
        return 0; // not yet covered — let parent handle
    }
}
